sql:
SELECT repositories.repo_name, owners.owner_name
FROM repositories
JOIN owners ON repositories.owner_id = owners.owner_id;

external_knowledge:
- 'detailed information' includes repository id, creation and update times, status, ahead and behind counts, default branch, privacy status, and visibility; 
- 'languages' and 'licenses' refer to the counts and concatenated names of these attributes for each repository; 
- 'owners' refers to the count and concatenated owner IDs for each repository.

sql:
SELECT user_id, COUNT(repo_id) AS repo_count
FROM stargazers
GROUP BY user_id;

SELECT repo_id, AVG(contribution_count) AS average_contributions
FROM repo_contributors
GROUP BY repo_id;

SELECT AVG(contributor_count) as avg_contributors
FROM (
    SELECT repo_id, COUNT(*) as contributor_count
    FROM repo_contributors 
    GROUP BY repo_id
);
